import{_ as t,o as e,c as r,a2 as l}from"./chunks/framework.Cr-Z7ngm.js";const c=JSON.parse('{"title":"期权基础","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"derivatives/options-basics.md","filePath":"zh-CN/derivatives/options-basics.md"}'),i={name:"derivatives/options-basics.md"};function o(n,a,h,d,p,s){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="期权基础" tabindex="-1">期权基础 <a class="header-anchor" href="#期权基础" aria-label="Permalink to &quot;期权基础&quot;">​</a></h1><p>期权定义、权利金、价内价外区分、交易时间、订单类型及行权结算规则。</p><h2 id="什么是股票期权" tabindex="-1">什么是股票期权 <a class="header-anchor" href="#什么是股票期权" aria-label="Permalink to &quot;什么是股票期权&quot;">​</a></h2><p>股票期权是一种以股票作为底层资产的标准化合约，可在交易所买卖并由结算所结算。</p><ul><li>按权利差异：分为看涨期权（Call）和看跌期权（Put）</li><li>按行权时间：分为美式期权（到期日及之前均可行权）和欧式期权（仅到期日行权）</li><li>按结算方式：分为现金交割和实物交割。大部分美股期权为实物交割的美式期权，指数期权一般为现金交割的欧式期权</li></ul><p>在股票期权中，买家为权利方，卖方为义务方：</p><table tabindex="0"><thead><tr><th></th><th>看涨期权（Call）</th><th>看跌期权（Put）</th></tr></thead><tbody><tr><td>买方（权利方）</td><td>有权以行权价买入正股</td><td>有权以行权价卖出正股</td></tr><tr><td>卖方（义务方）</td><td>有义务以行权价卖出正股</td><td>有义务以行权价买入正股</td></tr></tbody></table><h2 id="权利金" tabindex="-1">权利金 <a class="header-anchor" href="#权利金" aria-label="Permalink to &quot;权利金&quot;">​</a></h2><p>权利金是期权的交易价格，以每股为计价单位。最小交易 1 张合约，美股期权一般 1 张合约 = 100 股（公司行动可能导致合约规模变化）。</p><p>支付/收取权利金金额 = 期权价格 × 合约张数 × 期权乘数</p><p>示例：SPY 220304 C 429000，权利金价格 6.68 USD，持有该合约需支付 6.68 × 100 = 668 USD。行权时需支付 429 × 100 = 42,900 USD 获得 100 股 SPY。</p><h2 id="价内-itm-与价外-otm" tabindex="-1">价内（ITM）与价外（OTM） <a class="header-anchor" href="#价内-itm-与价外-otm" aria-label="Permalink to &quot;价内（ITM）与价外（OTM）&quot;">​</a></h2><p>根据期权行权价与股票市价的关系，区分为价内和价外：</p><ul><li>看涨期权：股票市价 &gt; 行权价 → 价内（ITM），否则为价外（OTM）</li><li>看跌期权：行权价 &gt; 股票市价 → 价内（ITM），否则为价外（OTM）</li></ul><p>价内期权具有真实价值。在长桥 App 期权链页面，蓝色部分为价内期权。</p><h2 id="交易时间" tabindex="-1">交易时间 <a class="header-anchor" href="#交易时间" aria-label="Permalink to &quot;交易时间&quot;">​</a></h2><p>美股期权交易时间：美东时间 09:30 - 16:00<br> 夏令时（3 月 - 11 月）：北京时间 21:30 - 04:00<br> 冬令时（11 月 - 次年 3 月）：北京时间 22:30 - 05:00<br> 注：大部分美股期权不支持盘前盘后，仅部分 ETF、ETN 期权延长交易至 16:15 EST。</p><h2 id="如何交易" tabindex="-1">如何交易 <a class="header-anchor" href="#如何交易" aria-label="Permalink to &quot;如何交易&quot;">​</a></h2><p>在股票详情页进入期权链页面，点击对应期权，选择「买入」或「卖出」，输入价格和数量即可下单。</p><p>支持的下单类型：限价单、市价单、条件单及长期单。</p><p><strong>保证金要求</strong>：买入看涨（Long Call）和买入看跌（Long Put）需支付权利金；卖出看涨（Short Call）和卖出看跌（Short Put）需预留保证金。</p><p><strong>期权入口限制</strong>：长桥当前支持大部分流通性高的美股期权，流通性较低的期权暂未覆盖，会不定期扩展可交易标的。</p><p><strong>成交优先级</strong>：美股期权受 BBO/NBBO 报价规则影响，订单可能被路由至其他交易所撮合。交易不活跃时不同交易所报价可能存在差异，价格更优的委托不一定优先成交。期权组合订单（Spread）中的单边订单也可能无法单独成交。</p><p><strong>免佣卡</strong>：期权交易不支持使用免佣卡。</p><h2 id="行权与结算" tabindex="-1">行权与结算 <a class="header-anchor" href="#行权与结算" aria-label="Permalink to &quot;行权与结算&quot;">​</a></h2><h3 id="行权规则" tabindex="-1">行权规则 <a class="header-anchor" href="#行权规则" aria-label="Permalink to &quot;行权规则&quot;">​</a></h3><p>期权到期后，长桥会对持有的期权仓位进行行权或放弃行权处理。不支持客户主动行权或主动放弃行权。</p><ul><li>实值期权（价内）：下个交易日开盘前自动行权。只要达到价内 0.01 USD 即可能触发行权</li><li>虚值期权（价外）：下个交易日开盘前放弃行权，期权仓位归 0 作废</li><li>卖空期权（Short Options）：即使处于价外，仍有可能被对手方提前行使义务（尤其在正股停牌时）</li></ul><h3 id="行权后" tabindex="-1">行权后 <a class="header-anchor" href="#行权后" aria-label="Permalink to &quot;行权后&quot;">​</a></h3><ul><li>买入看涨 / 卖出看跌：被行权时以行权价买入正股（张数 × 100 股）</li><li>买入看跌 / 卖出看涨：被行权时以行权价卖出正股（张数 × 100 股）。未持有足额正股时可能变成沽空处理</li></ul><h3 id="结算交收" tabindex="-1">结算交收 <a class="header-anchor" href="#结算交收" aria-label="Permalink to &quot;结算交收&quot;">​</a></h3><p>期权 T+1 交收，行权的正股 T+1 交收。</p><h2 id="末日期权保证金" tabindex="-1">末日期权保证金 <a class="header-anchor" href="#末日期权保证金" aria-label="Permalink to &quot;末日期权保证金&quot;">​</a></h2><p>末日期权（交易日当日到期）在到期日 11:00 - 14:00 EST，若期权变为价内或接近价内，会加收保证金（金额 = 当前市价 × 期权张数 × 100 股）。保证金不足时可能被强制平仓。</p><h2 id="公司行动处理" tabindex="-1">公司行动处理 <a class="header-anchor" href="#公司行动处理" aria-label="Permalink to &quot;公司行动处理&quot;">​</a></h2><p>发生公司行动时，已有持仓会被转入新仓位，期权价值不变，但每张期权行权对应的正股可能变化。</p><p>示例：1 张 BABA 期权对应 100 股，若 BABA 5 合 1，则每张期权权益变为合股后 20 股，权益价值不变。企业行动产生的新仓位可正常平仓但不能开仓。</p><h2 id="penny-interval-program" tabindex="-1">Penny Interval Program <a class="header-anchor" href="#penny-interval-program" aria-label="Permalink to &quot;Penny Interval Program&quot;">​</a></h2><p>Penny Interval Program 允许部分期权以最低 0.01 USD 增量交易。</p><p>名单内期权（QQQ/IWM/SPY 除外）：</p><ul><li>权利金 &lt; 3 USD：最低增量 0.01 USD</li><li>权利金 ≥ 3 USD：最低增量 0.05 USD</li><li>QQQ/IWM/SPY：所有期权最低增量 0.01 USD</li></ul><p>名单外期权：</p><ul><li>权利金 &lt; 3 USD：最低增量 0.05 USD</li><li>权利金 ≥ 3 USD：最低增量 0.10 USD</li></ul><p>如委托价格不符合增量要求，订单可能不会按预期优先级成交甚至被拒绝。</p><p><a href="https://www.theocc.com/market-data/market-data-reports/series-and-trading-data/penny-program" target="_blank" rel="noreferrer">名单查询</a></p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/derivatives/如何开通期权交易权限">如何开通期权交易权限</a> — 开通流程</li></ul>',47)])])}const b=t(i,[["render",o]]);export{c as __pageData,b as default};
